import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/base_classes/raymarch_3d_module_base.dart';

/// Shared smoke-test contract for generated 3D raymarched fractal modules.
///
/// Owns behavior assertions common to every module in this folder: module
/// identity, shader path, preset shape, and metadata linkage. It must not know
/// about individual fractal families, rendering UI, shader compilation, or app
/// orchestration.
void expectRaymarched3DModuleContract({
  required String className,
  required Raymarched3DModule Function() createModule,
  required String expectedId,
  required String expectedShader,
}) {
  test('$className instantiates', () {
    final m = createModule();
    expect(m.id, expectedId);
    expect(m.shader, expectedShader);
  });

  test('$className presets are well-formed', () {
    final m = createModule();
    expect(m.presets, isNotEmpty);
    for (final p in m.presets) {
      final preset = p as dynamic;
      expect(preset.id, isNotEmpty);
      expect(preset.name, isNotEmpty);
    }
  });

  test('$className metadata is consistent', () {
    final m = createModule();
    final metadata = m.metadata as dynamic;
    expect(metadata.id, m.id);
  });
}

